			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect (Subject+had+V3+Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past perfect (Subject+had+V3+Object)&lt;/td&gt;
		&lt;/tr&gt;
		&lt;tr&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past Continuous (Subject +was/were+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past Continuous (Subject +was/were+V1 +ing+ Object)&lt;/td&gt;
			&lt;td data-sheets-value=&quot;{&amp;quot;1&amp;quot;:2,&amp;quot;2&amp;quot;:&amp;quot;Past perfect continuous (Subject +had been+V1 +ing+ Object)&amp;quot;}&quot; style=&quot;text-align: center;&quot;&gt;Past perfect continuous (Subject +had been+V1 +ing+ Object)&lt;/td&gt;
